using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Leaderboard.Contracts;
namespace Games.Leaderboard.Discord;
public sealed class LeaderboardDiscordHandler(ILeaderboardClient client):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"balance","top","daily","globaltop");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);var cmd=p[0].ToLowerInvariant();var uid=DiscordCommand.UserId(c);var scope=DiscordCommand.ScopeId(c);var name=DiscordCommand.DisplayName(c);object r=cmd switch{"balance"=>await client.GetBalanceAsync(uid,scope,name,c.CancellationToken),"daily"=>await client.ClaimDailyAsync(uid,scope,name,c.CancellationToken),"globaltop"=>await client.GetGlobalTopAsync(10,c.CancellationToken),_=>await client.GetTopAsync(10,scope,c.CancellationToken)};await DiscordCommand.ReplyResultAsync(c,r,"Leaderboard");}}
public static class LeaderboardDiscordModule{public static IServiceCollection AddLeaderboardDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,LeaderboardDiscordHandler>();}
